import React, { useEffect, useState, useRef } from 'react';
import styled from 'styled-components';

const MonitorContainer = styled.div`
  position: fixed;
  top: 10px;
  right: 10px;
  background: rgba(0, 0, 0, 0.8);
  color: #00ff00;
  font-family: monospace;
  font-size: 12px;
  padding: 10px;
  border-radius: 5px;
  z-index: 10000;
  pointer-events: none;
  display: ${props => props.$visible ? 'block' : 'none'};
`;

const StatLine = styled.div`
  margin: 2px 0;
  color: ${props => {
    if (props.$type === 'fps') {
      return props.$value < 30 ? '#ff0000' : props.$value < 50 ? '#ffff00' : '#00ff00';
    }
    return '#00ff00';
  }};
`;

const PerformanceMonitor = React.memo(() => {
  const [stats, setStats] = useState({
    fps: 0,
    memory: 0,
    domNodes: 0,
    scrollTriggers: 0
  });
  const [visible, setVisible] = useState(false);
  const frameCount = useRef(0);
  const lastTime = useRef(performance.now());

  useEffect(() => {
    // Toggle visibility with Ctrl+Shift+P
    const handleKeyPress = (e) => {
      if (e.ctrlKey && e.shiftKey && e.key === 'P') {
        setVisible(prev => !prev);
      }
    };

    window.addEventListener('keydown', handleKeyPress);
    return () => window.removeEventListener('keydown', handleKeyPress);
  }, []);

  useEffect(() => {
    if (!visible) return;

    let animationId;
    
    const measurePerformance = () => {
      frameCount.current++;
      const currentTime = performance.now();
      
      // Calculate FPS every second
      if (currentTime >= lastTime.current + 1000) {
        const fps = Math.round((frameCount.current * 1000) / (currentTime - lastTime.current));
        const memory = performance.memory 
          ? Math.round(performance.memory.usedJSHeapSize / 1048576) 
          : 0;
        const domNodes = document.getElementsByTagName('*').length;
        
        // Count active ScrollTriggers
        let scrollTriggers = 0;
        if (window.ScrollTrigger) {
          scrollTriggers = window.ScrollTrigger.getAll().length;
        }
        
        setStats({
          fps,
          memory,
          domNodes,
          scrollTriggers
        });
        
        frameCount.current = 0;
        lastTime.current = currentTime;
      }
      
      animationId = requestAnimationFrame(measurePerformance);
    };
    
    animationId = requestAnimationFrame(measurePerformance);
    
    return () => {
      if (animationId) {
        cancelAnimationFrame(animationId);
      }
    };
  }, [visible]);

  return (
    <MonitorContainer $visible={visible}>
      <StatLine $type="fps" $value={stats.fps}>
        FPS: {stats.fps}
      </StatLine>
      {stats.memory > 0 && (
        <StatLine>
          Memory: {stats.memory} MB
        </StatLine>
      )}
      <StatLine>
        DOM Nodes: {stats.domNodes}
      </StatLine>
      <StatLine>
        ScrollTriggers: {stats.scrollTriggers}
      </StatLine>
    </MonitorContainer>
  );
});

PerformanceMonitor.displayName = 'PerformanceMonitor';

export default PerformanceMonitor;